import { quote, claim } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  describe("quote", () => {
    it.todo("should return base premium plus processing fee for a single plain item (first contract)");
    it.todo("should add 50% surcharge for a cursed item");
    it.todo("should add 30% surcharge for a highly enchanted item (enchantment >= 5)");
    it.todo("should apply 20% loyalty discount for long-standing customers (>= 2 years)");
    it.todo("should apply 15% discount on contracts after the first");
    it.todo("should use bulk deal price for 3 alike components");
  });

  describe("claim", () => {
    it.todo("should subtract 100G deductible from damage amount");
    it.todo("should reimburse 50% of damage for items with enchantment >= 8");
    it.todo("should reimburse 100% of damage for items made of dragon material");
    it.todo("should track remaining cap after a payout");
  });
});

